      const rail = new THREE.Mesh(
        new THREE.BoxGeometry(glassWidth + frame, frame, thin * 1.4),
        frameMat,
      );
      rail.position.set((spec.xMin + spec.xMax) / 2, yy, z);
      group.add(rail);
    }
