import * as THREE from 'three';
import { mergeVertices } from 'three/examples/jsm/utils/BufferGeometryUtils.js';
import { Brush, Evaluator, SUBTRACTION } from 'three-bvh-csg';
import type { Element } from '@bim-ai/core';

/**
 * KRN-14 / IFC-03 — subtract tall axis-aligned cut boxes for roof-hosted
 * void elements from the host roof geometry.
 *
 * The roof geometry is now closed (asymmetric-gable bottom face landed
 * alongside this fix), so three-bvh-csg's SUBTRACTION produces a clean
 * hole instead of silently no-op'ing. We also validate that the cut
 * footprint actually intersects the host roof bbox before attempting
 * CSG, and surface failures via console.warn rather than swallowing.
 */
export function applyDormerCutsToRoofGeom(
  geom: THREE.BufferGeometry,
  roof: Extract<Element, { kind: 'roof' }>,
  elementsById: Record<string, Element>,
  refElev: number,
): THREE.BufferGeometry {
  const dormers = Object.values(elementsById).filter(
    (e): e is Extract<Element, { kind: 'dormer' }> =>
      e.kind === 'dormer' && (e as Extract<Element, { kind: 'dormer' }>).hostRoofId === roof.id,
  );
  const roofOpenings = Object.values(elementsById).filter(
    (e): e is Extract<Element, { kind: 'roof_opening' }> =>
      e.kind === 'roof_opening' &&
      (e as Extract<Element, { kind: 'roof_opening' }>).hostRoofId === roof.id,
  );
  if (dormers.length === 0 && roofOpenings.length === 0) return geom;
  const roofBbox = computeRoofBboxMm(roof);
  try {
    // three-bvh-csg requires both inputs to share the same attribute
    // set, indexed, with normals. Strip everything except position then
    // re-add normal + index via the helpers — keeps both sides aligned.
    function normaliseForCsg(input: THREE.BufferGeometry): THREE.BufferGeometry {
      const g = new THREE.BufferGeometry();
      const pos = input.getAttribute('position');
      g.setAttribute('position', pos);
      if (input.index) g.setIndex(input.index);
      const indexed = g.index ? g : mergeVertices(g);
      indexed.computeVertexNormals();
      return indexed;
    }
    const csgInput = normaliseForCsg(geom);
    const evaluator = new Evaluator();
    // The roof builders emit position + normal but no uv; restrict the
    // evaluator's relevant-attribute set to match. (The lib defaults to
    // ['position', 'uv', 'normal'] and crashes on missing uv with
    // "Cannot read properties of undefined (reading 'array')".)
    evaluator.attributes = ['position', 'normal'];
    let brush = new Brush(csgInput);
    brush.updateMatrixWorld();
    let cutsApplied = 0;
    const cuts: Array<{
      id: string;
      kind: 'dormer' | 'roof_opening';
      footprint: { minX: number; maxX: number; minY: number; maxY: number };
    }> = [
      ...dormers.map((d) => ({
        id: d.id,
        kind: 'dormer' as const,
        footprint: computeDormerFootprintMm(d, roof),
      })),
      ...roofOpenings.map((o) => ({
        id: o.id,
        kind: 'roof_opening' as const,
        footprint: computeRoofOpeningFootprintMm(o),
      })),
    ];
    for (const cut of cuts) {
      const fp = cut.footprint;
      if (!bboxesOverlap(fp, roofBbox)) {
        console.warn(
          `[dormerRoofCut] ${cut.kind} ${cut.id} footprint does not intersect host roof ${roof.id} bbox; skipping CSG cut.`,
        );
        continue;
      }
      // World coords: plan-X → world-X, plan-Y → world-Z (no negation),
      // matching makeRoofMassMesh + wall builders. The earlier negated
      // convention put the cutter on the opposite side of world-origin from
      // the host roof, so SUBTRACTION ran but did nothing inside the
      // visible roof volume.
      // Expand 5 cm past the dormer footprint so the cut boundary is behind the
      // dormer wall faces, letting depth testing occlude CSG edge lines.
      const overlapM = 0.05;
      const xMin = fp.minX / 1000 - overlapM;
      const xMax = fp.maxX / 1000 + overlapM;
      const zMin = fp.minY / 1000 - overlapM;
      const zMax = fp.maxY / 1000 + overlapM;
      const widthM = xMax - xMin;
      const depthM = zMax - zMin;
      if (widthM <= 0 || depthM <= 0) {
        console.warn(
          `[dormerRoofCut] ${cut.kind} ${cut.id} has non-positive footprint (${widthM}m x ${depthM}m); skipping CSG cut.`,
        );
        continue;
      }
      const cutHeightM = 30;
      const baseY = refElev;
      const boxRaw = new THREE.BoxGeometry(widthM, cutHeightM, depthM);
      const cutter = new Brush(normaliseForCsg(boxRaw));
      cutter.position.set((xMin + xMax) / 2, baseY + cutHeightM / 2, (zMin + zMax) / 2);
      cutter.updateMatrixWorld();
      brush = evaluator.evaluate(brush, cutter, SUBTRACTION);
      brush.updateMatrixWorld();
      cutsApplied += 1;
    }
    if (cutsApplied === 0) return geom;
    const cutGeom = brush.geometry;
    cutGeom.computeVertexNormals();
    return cutGeom;
  } catch (err) {
    console.warn(
      `[dormerRoofCut] CSG SUBTRACTION failed on roof ${roof.id} (${dormers.length} dormer(s), ${roofOpenings.length} roof opening(s)); rendering uncut.`,
      err,
    );
    return geom;
  }
}

function computeRoofBboxMm(roof: Extract<Element, { kind: 'roof' }>): {
  minX: number;
  maxX: number;
  minY: number;
  maxY: number;
} {
  const xs = roof.footprintMm.map((p) => p.xMm);
  const ys = roof.footprintMm.map((p) => p.yMm);
  return {
    minX: Math.min(...xs),
    maxX: Math.max(...xs),
    minY: Math.min(...ys),
    maxY: Math.max(...ys),
  };
}

function bboxesOverlap(
  a: { minX: number; maxX: number; minY: number; maxY: number },
  b: { minX: number; maxX: number; minY: number; maxY: number },
): boolean {
  return a.maxX > b.minX && a.minX < b.maxX && a.maxY > b.minY && a.minY < b.maxY;
}

function computeDormerFootprintMm(
  dormer: Extract<Element, { kind: 'dormer' }>,
  hostRoof: Extract<Element, { kind: 'roof' }>,
): { minX: number; maxX: number; minY: number; maxY: number } {
  const xs = hostRoof.footprintMm.map((p) => p.xMm);
  const ys = hostRoof.footprintMm.map((p) => p.yMm);
  const minRx = Math.min(...xs);
  const maxRx = Math.max(...xs);
  const minRy = Math.min(...ys);
  const maxRy = Math.max(...ys);
  const cx = (minRx + maxRx) / 2;
  const cy = (minRy + maxRy) / 2;
  const spanX = maxRx - minRx;
  const spanY = maxRy - minRy;
  const ridgeAlongX =
    hostRoof.ridgeAxis === 'x' ? true : hostRoof.ridgeAxis === 'z' ? false : spanX >= spanY;
  const dx = ridgeAlongX ? dormer.positionOnRoof.alongRidgeMm : dormer.positionOnRoof.acrossRidgeMm;
  const dy = ridgeAlongX ? dormer.positionOnRoof.acrossRidgeMm : dormer.positionOnRoof.alongRidgeMm;
  const centreX = cx + dx;
  const centreY = cy + dy;
  const halfW = dormer.widthMm / 2;
  const halfD = dormer.depthMm / 2;
  if (ridgeAlongX) {
    return {
      minX: centreX - halfW,
      maxX: centreX + halfW,
      minY: centreY - halfD,
      maxY: centreY + halfD,
    };
  }
  return {
    minX: centreX - halfD,
    maxX: centreX + halfD,
    minY: centreY - halfW,
    maxY: centreY + halfW,
  };
}

function computeRoofOpeningFootprintMm(opening: Extract<Element, { kind: 'roof_opening' }>): {
  minX: number;
  maxX: number;
  minY: number;
  maxY: number;
} {
  const xs = opening.boundaryMm.map((p) => p.xMm);
  const ys = opening.boundaryMm.map((p) => p.yMm);
  return {
    minX: Math.min(...xs),
    maxX: Math.max(...xs),
    minY: Math.min(...ys),
    maxY: Math.max(...ys),
  };
}

import * as THREE from 'three';
import { Sky } from 'three/addons/objects/Sky.js';
import { liveTokenReader, type ElementCategoryToken, type ViewportPaintBundle } from './materials';

export const CATEGORY_FALLBACK_COLOR_HEX = '#cbd5e1';

export function categoryColorOr(
  bundle: ViewportPaintBundle | null,
  cat: ElementCategoryToken,
): string {
  return bundle?.categories[cat]?.color ?? CATEGORY_FALLBACK_COLOR_HEX;
}

export function readToken(name: string, fallback: string): string {
  const v = liveTokenReader().read(name);
  return v && v.trim().length > 0 ? v : fallback;
}

/** Resolve a CSS color token to an rgb() string that Three.js can parse.
 * CSS Color Level 4 hsl() uses spaces (e.g. "hsl(0 0% 100%)") which
 * Three.js does not support — routing through a DOM element forces the
 * browser to resolve it to "rgb(r, g, b)". */
export function readColorToken(name: string, fallback: string): string {
  if (typeof document === 'undefined') return fallback;
  try {
    const el = document.createElement('div');
    el.style.display = 'none';
    el.style.color = `var(${name}, ${fallback})`;
    document.body.appendChild(el);
    const resolved = getComputedStyle(el).color;
    document.body.removeChild(el);
    return resolved || fallback;
  } catch {
    return fallback;
  }
}

export function sunPositionFromAzEl(
  azimuthDeg: number,
  elevationDeg: number,
  radiusM = 80,
): THREE.Vector3 {
  const az = THREE.MathUtils.degToRad(azimuthDeg);
  const el = THREE.MathUtils.degToRad(elevationDeg);
  return new THREE.Vector3(
    radiusM * Math.cos(el) * Math.sin(az),
    radiusM * Math.sin(el),
    radiusM * Math.cos(el) * Math.cos(az),
  );
}

export function buildSkyEnvMap(
  renderer: THREE.WebGLRenderer,
  azimuthDeg: number,
  elevationDeg: number,
): THREE.Texture {
  const sky = new Sky();
  sky.scale.setScalar(450000);
  const u = sky.material.uniforms;
  u['turbidity'].value = 3;
  u['rayleigh'].value = 0.5;
  u['mieCoefficient'].value = 0.005;
  u['mieDirectionalG'].value = 0.8;
  const phi = THREE.MathUtils.degToRad(90 - elevationDeg);
  const theta = THREE.MathUtils.degToRad(azimuthDeg);
  u['sunPosition'].value.setFromSphericalCoords(1, phi, theta);
  const pmrem = new THREE.PMREMGenerator(renderer);
  pmrem.compileEquirectangularShader();
  const tempScene = new THREE.Scene();
  tempScene.add(sky);
  const envTexture = pmrem.fromScene(tempScene).texture;
  pmrem.dispose();
  (sky.material as THREE.ShaderMaterial).dispose();
  sky.geometry.dispose();
  return envTexture;
}

export function addEdges(mesh: THREE.Mesh, thresholdAngleDeg = 20): THREE.LineSegments {
  const color = readToken('--draft-cut', '#1d2330');
  const edges = new THREE.EdgesGeometry(mesh.geometry, thresholdAngleDeg);
  const mat = new THREE.LineBasicMaterial({
    color,
    linewidth: 1,
    transparent: true,
    opacity: 0.38,
  });
  const lines = new THREE.LineSegments(edges, mat);
  lines.renderOrder = 1;
  lines.castShadow = false;
  lines.receiveShadow = false;
  mesh.add(lines);
  return lines;
}

import type { Element } from '@bim-ai/core';

type RoofElem = Extract<Element, { kind: 'roof' }>;

function elevationMForLevel(levelId: string, elementsById: Record<string, Element>): number {
  const lv = elementsById[levelId];
  return lv?.kind === 'level'
    ? ((lv as Extract<Element, { kind: 'level' }>).elevationMm ?? 0) / 1000
    : 0;
}

function xzBoundsMm(poly: Array<{ xMm: number; yMm: number }>) {
  let minX = Number.POSITIVE_INFINITY;
  let maxX = Number.NEGATIVE_INFINITY;
  let minZ = Number.POSITIVE_INFINITY;
  let maxZ = Number.NEGATIVE_INFINITY;
  for (const p of poly) {
    if (p.xMm < minX) minX = p.xMm;
    if (p.xMm > maxX) maxX = p.xMm;
    if (p.yMm < minZ) minZ = p.yMm;
    if (p.yMm > maxZ) maxZ = p.yMm;
  }
  return { minX, maxX, minZ, maxZ, spanX: maxX - minX, spanZ: maxZ - minZ };
}

export function roofHeightAtPoint(
  roof: RoofElem,
  elementsById: Record<string, Element>,
  xMm: number,
  zMm: number,
): number {
  const refElev = elevationMForLevel(roof.referenceLevelId, elementsById);
  const wallsAtRefLevel = Object.values(elementsById).filter(
    (e): e is Extract<Element, { kind: 'wall' }> =>
      e.kind === 'wall' &&
      (e as Extract<Element, { kind: 'wall' }>).levelId === roof.referenceLevelId,
  );
  const wallTopM =
    wallsAtRefLevel.length > 0
      ? Math.max(...wallsAtRefLevel.map((w) => (w.heightMm ?? 0) / 1000))
      : 0;
  const eaveY = refElev + wallTopM;

  if (roof.roofGeometryMode === 'mass_box') {
    return eaveY;
  }

  const rawSlopeDeg = roof.slopeDeg ?? 25;
  const clampedDeg = Math.min(70, Math.max(5, Number(rawSlopeDeg)));
  const slopeRad = (clampedDeg * Math.PI) / 180;

  const b = xzBoundsMm(roof.footprintMm ?? []);
  const ox0 = b.minX / 1000;
  const ox1 = b.maxX / 1000;
  const oz0 = b.minZ / 1000;
  const oz1 = b.maxZ / 1000;

  const spanXm = b.spanX / 1000;
  const spanZm = b.spanZ / 1000;

  let ridgeAlongX: boolean;
  if (roof.ridgeAxis === 'x') ridgeAlongX = true;
  else if (roof.ridgeAxis === 'z') ridgeAlongX = false;
  else ridgeAlongX = spanXm >= spanZm;

  const x = xMm / 1000;
  const z = zMm / 1000;
  const tan = Math.tan(slopeRad);

  if (roof.roofGeometryMode === 'asymmetric_gable') {
    const ridgeOffsetM = (roof.ridgeOffsetTransverseMm ?? 0) / 1000;
    const eaveLeftY =
      roof.eaveHeightLeftMm != null ? refElev + roof.eaveHeightLeftMm / 1000 : eaveY;
    const eaveRightY =
      roof.eaveHeightRightMm != null ? refElev + roof.eaveHeightRightMm / 1000 : eaveY;
    if (ridgeAlongX) {
      const halfSpan = (oz1 - oz0) / 2;
      const center = (oz0 + oz1) / 2;
      const offset = Math.max(-halfSpan + 1e-6, Math.min(halfSpan - 1e-6, ridgeOffsetM));
      const rz = center + offset;
      const leftRun = halfSpan + offset;
      const ridgeY = eaveLeftY + leftRun * tan;
      if (z <= rz) {
        const t = leftRun > 0 ? (z - oz0) / leftRun : 0;
        return eaveLeftY + Math.max(0, Math.min(1, t)) * (ridgeY - eaveLeftY);
      } else {
        const rightRun = halfSpan - offset;
        const t = rightRun > 0 ? (z - rz) / rightRun : 0;
        return ridgeY + Math.max(0, Math.min(1, t)) * (eaveRightY - ridgeY);
      }
    } else {
      const halfSpan = (ox1 - ox0) / 2;
      const center = (ox0 + ox1) / 2;
      const offset = Math.max(-halfSpan + 1e-6, Math.min(halfSpan - 1e-6, ridgeOffsetM));
      const rx = center + offset;
      const leftRun = halfSpan + offset;
      const ridgeY = eaveLeftY + leftRun * tan;
      if (x <= rx) {
        const t = leftRun > 0 ? (x - ox0) / leftRun : 0;
        return eaveLeftY + Math.max(0, Math.min(1, t)) * (ridgeY - eaveLeftY);
      } else {
        const rightRun = halfSpan - offset;
        const t = rightRun > 0 ? (x - rx) / rightRun : 0;
        return ridgeY + Math.max(0, Math.min(1, t)) * (eaveRightY - ridgeY);
      }
    }
  }

  if (roof.roofGeometryMode === 'hip') {
    if (ridgeAlongX) {
      const halfSpanZ = (oz1 - oz0) / 2;
      const dz = halfSpanZ - Math.abs(z - (oz0 + oz1) / 2);
      const rx0 = ox0 + halfSpanZ;
      const rx1 = ox1 - halfSpanZ;
      let dx: number;
      if (rx0 >= rx1) {
        dx = (ox1 - ox0) / 2 - Math.abs(x - (ox0 + ox1) / 2);
      } else {
        dx = x < rx0 ? x - ox0 : x > rx1 ? ox1 - x : halfSpanZ;
      }
      return eaveY + Math.max(0, Math.min(dz, dx)) * tan;
    } else {
      const halfSpanX = (ox1 - ox0) / 2;
      const dx = halfSpanX - Math.abs(x - (ox0 + ox1) / 2);
      const rz0 = oz0 + halfSpanX;
      const rz1 = oz1 - halfSpanX;
      let dz: number;
      if (rz0 >= rz1) {
        dz = (oz1 - oz0) / 2 - Math.abs(z - (oz0 + oz1) / 2);
      } else {
        dz = z < rz0 ? z - oz0 : z > rz1 ? oz1 - z : halfSpanX;
      }
      return eaveY + Math.max(0, Math.min(dx, dz)) * tan;
    }
  }

  // gable (default)
  if (ridgeAlongX) {
    const halfSpan = (oz1 - oz0) / 2;
    return eaveY + Math.max(0, halfSpan - Math.abs(z - (oz0 + oz1) / 2)) * tan;
  } else {
    const halfSpan = (ox1 - ox0) / 2;
    return eaveY + Math.max(0, halfSpan - Math.abs(x - (ox0 + ox1) / 2)) * tan;
  }
}

