13	type DormerElem = Extract<Element, { kind: 'dormer' }>;
14	type RoofElem = Extract<Element, { kind: 'roof' }>;
15	type WallElem = Extract<Element, { kind: 'wall' }>;
16	
17	/**
18	 * KRN-14 — compute the dormer footprint (axis-aligned rectangle) in plan
19	 * coordinates (mm), given the host roof's footprint and the dormer's
20	 * positionOnRoof. Convention:
21	 *   - the longer span axis of the host footprint is taken as the ridge axis
22	 *     (matching `makeRoofMassMesh`)
23	 *   - `alongRidgeMm` is a signed offset of the dormer centre along the ridge
24	 *     direction from the footprint centre
25	 *   - `acrossRidgeMm` is a signed offset perpendicular to the ridge from the
26	 *     footprint centre (positive = +plan-X for ridges along plan-Y, or
27	 *     +plan-Y for ridges along plan-X)
28	 */
29	export function dormerFootprintMm(
30	  dormer: DormerElem,
31	  hostRoof: RoofElem,
32	): { minX: number; maxX: number; minY: number; maxY: number; ridgeAlongX: boolean } {
33	  const xs = hostRoof.footprintMm.map((p) => p.xMm);
34	  const ys = hostRoof.footprintMm.map((p) => p.yMm);
35	  const minRx = Math.min(...xs);
36	  const maxRx = Math.max(...xs);
37	  const minRy = Math.min(...ys);
38	  const maxRy = Math.max(...ys);
39	  const cx = (minRx + maxRx) / 2;
40	  const cy = (minRy + maxRy) / 2;
41	  const spanX = maxRx - minRx;
42	  const spanY = maxRy - minRy;
43	  // Match makeRoofMassMesh's heuristic when ridgeAxis is unset: longer plan
44	  // axis becomes the ridge.
45	  const ridgeAlongX =
46	    hostRoof.ridgeAxis === 'x' ? true : hostRoof.ridgeAxis === 'z' ? false : spanX >= spanY;
47	
48	  const dx = ridgeAlongX ? dormer.positionOnRoof.alongRidgeMm : dormer.positionOnRoof.acrossRidgeMm;
49	  const dy = ridgeAlongX ? dormer.positionOnRoof.acrossRidgeMm : dormer.positionOnRoof.alongRidgeMm;
50	  const centreX = cx + dx;
51	  const centreY = cy + dy;
52	
53	  const halfWidth = dormer.widthMm / 2;
54	  const halfDepth = dormer.depthMm / 2;
55	
56	  // Width runs along the ridge; depth runs across.
57	  if (ridgeAlongX) {
58	    return {
59	      minX: centreX - halfWidth,
60	      maxX: centreX + halfWidth,
61	      minY: centreY - halfDepth,
62	      maxY: centreY + halfDepth,
63	      ridgeAlongX,
64	    };
65	  }
66	  return {
67	    minX: centreX - halfDepth,
68	    maxX: centreX + halfDepth,
69	    minY: centreY - halfWidth,
70	    maxY: centreY + halfWidth,
71	    ridgeAlongX,
72	  };
73	}
74	
75	/**
76	 * Build a dormer Group: cheek walls + back wall + flat dormer roof. The
77	 * "front" face of the dormer is left open (this is where hosted glass doors
78	 * go; in the demo seed they sit on the upper-volume east wall, which serves
79	 * as the dormer's interior back wall, with the open side pointing toward
80	 * the deck).
81	 */
82	export function makeDormerMesh(
83	  dormer: DormerElem,
84	  elementsById: Record<string, Element>,
85	  paint: ViewportPaintBundle | null,
86	): THREE.Group {
87	  const group = new THREE.Group();
88	  group.userData.bimPickId = dormer.id;
89	
90	  const hostRoof = elementsById[dormer.hostRoofId];
91	  if (!hostRoof || hostRoof.kind !== 'roof') return group;
92	
93	  const fp = dormerFootprintMm(dormer, hostRoof);
94	
95	  // Reference elevation: top of upper-floor walls (eave plate) at host roof's
96	  // reference level. Use the same heuristic as makeRoofMassMesh.
97	  const refElev = elevationMForLevel(hostRoof.referenceLevelId, elementsById);
98	  const wallsAtRef = Object.values(elementsById).filter(
99	    (e): e is WallElem =>
100	      e.kind === 'wall' && (e as WallElem).levelId === hostRoof.referenceLevelId,
101	  );
102	  const centreXmm = (fp.minX + fp.maxX) / 2;
103	  const centreYmm = (fp.minY + fp.maxY) / 2;
104	  const wallTopM =
105	    wallsAtRef.length > 0 ? Math.max(...wallsAtRef.map((w) => (w.heightMm ?? 0) / 1000)) : 0;
106	  const openTowardPositiveAcross = (dormer.positionOnRoof.acrossRidgeMm ?? 0) >= 0;
107	  // Sample at the eave-facing edge (lowest roof point under the dormer) so the
108	  // dormer base sits flush with the roof instead of floating above it.
109	  const eaveEdgeXmm = fp.ridgeAlongX ? centreXmm : openTowardPositiveAcross ? fp.maxX : fp.minX;
110	  const eaveEdgeYmm = fp.ridgeAlongX ? (openTowardPositiveAcross ? fp.maxY : fp.minY) : centreYmm;
111	  const roofPlaneY = roofHeightAtPoint(hostRoof, elementsById, eaveEdgeXmm, eaveEdgeYmm);
112	  const baseY = Math.max(refElev + wallTopM, roofPlaneY - 0.05);
113	  const wallHeightM = THREE.MathUtils.clamp(dormer.wallHeightMm / 1000, 0.5, 8);
114	  const topY = baseY + wallHeightM;
115	
116	  // World coords: plan-X → world-X, plan-Y → world-Z (no negation,
117	  // matching the wall + roof builders elsewhere in viewport/meshBuilders.ts).
118	  // The earlier negated convention placed dormer geometry ~plan-depth metres
119	  // away from the host building in world Z, rendering it invisible.
120	  const xMin = fp.minX / 1000;
121	  const xMax = fp.maxX / 1000;
122	  const zMin = fp.minY / 1000;
123	  const zMax = fp.maxY / 1000;
124	  const widthM = xMax - xMin;
125	  const depthM = zMax - zMin;
126	  const cheekThickM = 0.18;
127	  // Extra reach past the CSG-cut boundary so dormer walls physically occlude
128	  // the edge lines that three-bvh-csg creates at the cut perimeter.
129	  // renderOrder=1 means edge lines render last and win coplanar Z-fights, so
130	  // the geometry must extend PAST the cut boundary (cut expands 5 cm, geometry
131	  // 10 cm) to put solid faces in front of the cut edge lines depth-test-wise.
132	  const overlapM = 0.1;
133	  const roofThickM = 0.12;
134	
135	  const wallSpec = resolveMaterial(dormer.wallMaterialKey ?? null);
136	  const wallColor = wallSpec?.baseColor ?? '#f4f4f0';
137	  const wallIsRender = wallSpec?.category === 'render' || wallSpec?.category === 'cladding';
138	  const wallMat = new THREE.MeshStandardMaterial({
139	    color: new THREE.Color(wallColor),
140	    roughness: wallSpec?.roughness ?? 0.92,
141	    metalness: wallSpec?.metalness ?? 0,
142	    envMapIntensity: wallIsRender ? 0.15 : 1.0,
143	  });
144	
145	  const roofSpec = resolveMaterial(dormer.roofMaterialKey ?? null);
146	  const roofColor = roofSpec?.baseColor ?? wallColor;
147	  const roofMat = new THREE.MeshStandardMaterial({
148	    color: new THREE.Color(roofColor),
149	    roughness: roofSpec?.roughness ?? 0.85,
150	    metalness: roofSpec?.metalness ?? 0,
151	    envMapIntensity: roofSpec?.category === 'metal_roof' ? 0.4 : 0.15,
152	  });
153	  void categoryColorOr;
154	
155	  // Two cheek walls running along the depth direction (across ridge for
156	  // ridgeAlongX=false). For our target house ridge is along plan-Y, so the
157	  // dormer width axis = plan-Y = world-Z, depth axis = plan-X = world-X.
158	  // Cheek walls are perpendicular to the ridge i.e. in the X-Y world plane.
159	  if (fp.ridgeAlongX) {
160	    // Cheeks are walls of constant X (one at xMin, one at xMax), running
161	    // along world-Z for the dormer depth. Extended by overlapM outward past
162	    // the CSG cut boundary so the cheek face sits in front of the cut edge lines.
163	    for (const xCenter of [
164	      xMin + (cheekThickM - overlapM) / 2,
165	      xMax - (cheekThickM - overlapM) / 2,
166	    ]) {
167	      const cheek = new THREE.Mesh(
168	        new THREE.BoxGeometry(cheekThickM + overlapM, wallHeightM, depthM + 2 * overlapM),
169	        wallMat,
170	      );
171	      cheek.position.set(xCenter, baseY + wallHeightM / 2, (zMin + zMax) / 2);
172	      addEdges(cheek);
173	      group.add(cheek);
174	    }
175	    // Back wall faces the ridge; the open glazed face points down the roof
176	    // slope toward the eave side where the dormer was placed.
177	    const backWallZ = openTowardPositiveAcross ? zMin + cheekThickM / 2 : zMax - cheekThickM / 2;
178	    const backWall = new THREE.Mesh(
179	      new THREE.BoxGeometry(widthM, wallHeightM, cheekThickM),
180	      wallMat,
181	    );
182	    backWall.position.set((xMin + xMax) / 2, baseY + wallHeightM / 2, backWallZ);
183	    addEdges(backWall);
184	    group.add(backWall);
185	    addDormerFaceWindow(group, {
186	      ridgeAlongX: true,
187	      openTowardPositiveAcross,
188	      xMin,
189	      xMax,
190	      zMin,
191	      zMax,
192	      baseY,
193	      wallHeightM,
194	      cheekThickM,
195	      wallMat,
196	    });
197	  } else {
198	    // Ridge along plan-Y → ridge along world-Z. Cheek walls are at zMin,zMax
199	    // running along world-X. Extended by overlapM outward past the CSG cut boundary.
200	    for (const zCenter of [
201	      zMin + (cheekThickM - overlapM) / 2,
202	      zMax - (cheekThickM - overlapM) / 2,
203	    ]) {
204	      const cheek = new THREE.Mesh(
205	        new THREE.BoxGeometry(widthM + 2 * overlapM, wallHeightM, cheekThickM + overlapM),
206	        wallMat,
207	      );
208	      cheek.position.set((xMin + xMax) / 2, baseY + wallHeightM / 2, zCenter);
209	      addEdges(cheek);
210	      group.add(cheek);
211	    }
212	    // Back wall faces the ridge; the open glazed face points down the roof
213	    // slope toward the eave side where the dormer was placed.
214	    const backWallX = openTowardPositiveAcross ? xMin + cheekThickM / 2 : xMax - cheekThickM / 2;
215	    const backWall = new THREE.Mesh(
216	      new THREE.BoxGeometry(cheekThickM, wallHeightM, depthM),
217	      wallMat,
218	    );
219	    backWall.position.set(backWallX, baseY + wallHeightM / 2, (zMin + zMax) / 2);
220	    addEdges(backWall);
221	    group.add(backWall);
222	    addDormerFaceWindow(group, {
223	      ridgeAlongX: false,
224	      openTowardPositiveAcross,
225	      xMin,
226	      xMax,
227	      zMin,
228	      zMax,
229	      baseY,
230	      wallHeightM,
231	      cheekThickM,
232	      wallMat,
233	    });
234	  }
235	
236	  const roofKind = dormer.dormerRoofKind ?? 'flat';
237	  const ridgeHeightM =
238	    dormer.ridgeHeightMm != null ? Math.max(0.1, dormer.ridgeHeightMm / 1000) : 1.2;
239	  const eaveCenterX = (xMin + xMax) / 2;
240	  const eaveCenterZ = (zMin + zMax) / 2;
241	
242	  if (roofKind === 'gable') {
243	    const roof = buildGableDormerRoof(
244	      widthM,
245	      depthM,
246	      roofThickM,
247	      ridgeHeightM,
248	      fp.ridgeAlongX,
249	      roofMat,
250	    );
251	    roof.position.set(eaveCenterX, topY, eaveCenterZ);
252	    addEdges(roof);
253	    group.add(roof);
254	  } else if (roofKind === 'hipped') {
255	    const roof = buildHippedDormerRoof(
256	      widthM,
257	      depthM,
258	      roofThickM,
259	      ridgeHeightM,
260	      fp.ridgeAlongX,
261	      roofMat,
262	    );
263	    roof.position.set(eaveCenterX, topY, eaveCenterZ);
264	    addEdges(roof);
265	    group.add(roof);
266	  } else {
267	    const roofSlab = new THREE.Mesh(new THREE.BoxGeometry(widthM, roofThickM, depthM), roofMat);
268	    roofSlab.position.set(eaveCenterX, topY + roofThickM / 2, eaveCenterZ);
269	    addEdges(roofSlab);
270	    group.add(roofSlab);
271	  }
272	
273	  // Floor slab — seals the dormer box bottom when there is no floor opening,
274	  // hiding the CSG cut-hole and the roof slope visible through the glazed face.
275	  if (!dormer.hasFloorOpening) {
276	    const floorThickM = 0.12;
277	    const floorMat = new THREE.MeshStandardMaterial({
278	      color: new THREE.Color('#c8c4bc'),
279	      roughness: 0.88,
280	      metalness: 0,
281	    });
282	    // Expanded by overlapM on all sides so the slab face sits in front of all
283	    // four CSG cut-boundary edge lines and occludes them via depth testing.
284	    const floor = new THREE.Mesh(
285	      new THREE.BoxGeometry(widthM + 2 * overlapM, floorThickM, depthM + 2 * overlapM),
286	      floorMat,
287	    );
288	    // Top of slab flush with the adjacent roof surface at the eave-facing edge.
289	    floor.position.set((xMin + xMax) / 2, roofPlaneY - floorThickM / 2, (zMin + zMax) / 2);
290	    addEdges(floor);
291	    group.add(floor);
292	  }
293	
294	  void paint;
295	  return group;
296	}
297	
298	function addDormerFaceWindow(
299	  group: THREE.Group,
300	  spec: {
301	    ridgeAlongX: boolean;
302	    openTowardPositiveAcross: boolean;
303	    xMin: number;
304	    xMax: number;
305	    zMin: number;
306	    zMax: number;
307	    baseY: number;
308	    wallHeightM: number;
309	    cheekThickM: number;
310	    wallMat: THREE.MeshStandardMaterial;
311	  },
312	): void {
313	  const glassSpec = resolveMaterial('glass_clear');
314	  const frameSpec = resolveMaterial('aluminium_dark_grey');
315	  const glassMat = new THREE.MeshStandardMaterial({
316	    color: new THREE.Color(glassSpec?.baseColor ?? '#b8d6e6'),
317	    roughness: glassSpec?.roughness ?? 0.05,
318	    metalness: glassSpec?.metalness ?? 0,
319	    transparent: true,
320	    opacity: 0.62,
321	    envMapIntensity: 0.9,
322	  });
323	  const frameMat = new THREE.MeshStandardMaterial({
324	    color: new THREE.Color(frameSpec?.baseColor ?? '#343638'),
325	    roughness: frameSpec?.roughness ?? 0.35,
326	    metalness: frameSpec?.metalness ?? 0.4,
327	  });
328	
329	  const widthM = spec.xMax - spec.xMin;
330	  const depthM = spec.zMax - spec.zMin;
331	  const glassHeight = Math.max(0.65, spec.wallHeightM * 0.52);
332	  const y = spec.baseY + spec.wallHeightM * 0.48;
333	  const frame = 0.045;
334	  const thin = 0.04;
335	
336	  // Sill height = the gap between the dormer base and the bottom of the glass pane.
337	  const sillHeight = Math.max(0, spec.wallHeightM * 0.48 - glassHeight / 2);
338	
339	  if (spec.ridgeAlongX) {
340	    const glassWidth = Math.max(0.7, widthM * 0.72);
341	    const z = spec.openTowardPositiveAcross
342	      ? spec.zMax - spec.cheekThickM / 2
343	      : spec.zMin + spec.cheekThickM / 2;
344	    const glass = new THREE.Mesh(new THREE.BoxGeometry(glassWidth, glassHeight, thin), glassMat);
345	    glass.position.set((spec.xMin + spec.xMax) / 2, y, z);
346	    group.add(glass);
347	    for (const x of [
348	      (spec.xMin + spec.xMax) / 2 - glassWidth / 2,
349	      (spec.xMin + spec.xMax) / 2,
350	      (spec.xMin + spec.xMax) / 2 + glassWidth / 2,
351	    ]) {
352	      const mullion = new THREE.Mesh(
353	        new THREE.BoxGeometry(frame, glassHeight + frame, thin * 1.4),
354	        frameMat,
355	      );
356	      mullion.position.set(x, y, z);
357	      group.add(mullion);
358	    }
359	    for (const yy of [y - glassHeight / 2, y + glassHeight / 2]) {
360	      const rail = new THREE.Mesh(
361	        new THREE.BoxGeometry(glassWidth + frame, frame, thin * 1.4),
362	        frameMat,
363	      );
364	      rail.position.set((spec.xMin + spec.xMax) / 2, yy, z);
365	      group.add(rail);
366	    }
367	    if (sillHeight > 0.01) {
368	      const sill = new THREE.Mesh(
369	        new THREE.BoxGeometry(widthM, sillHeight, thin * 1.4),
370	        spec.wallMat,
371	      );
372	      sill.position.set((spec.xMin + spec.xMax) / 2, spec.baseY + sillHeight / 2, z);
373	      group.add(sill);
374	    }
375	    return;
376	  }
377	
378	  const glassWidth = Math.max(0.7, depthM * 0.72);
379	  const x = spec.openTowardPositiveAcross
380	    ? spec.xMax - spec.cheekThickM / 2
381	    : spec.xMin + spec.cheekThickM / 2;
382	  const glass = new THREE.Mesh(new THREE.BoxGeometry(thin, glassHeight, glassWidth), glassMat);
383	  glass.position.set(x, y, (spec.zMin + spec.zMax) / 2);
384	  group.add(glass);
385	  for (const z of [
386	    (spec.zMin + spec.zMax) / 2 - glassWidth / 2,
387	    (spec.zMin + spec.zMax) / 2,
388	    (spec.zMin + spec.zMax) / 2 + glassWidth / 2,
389	  ]) {
390	    const mullion = new THREE.Mesh(
391	      new THREE.BoxGeometry(thin * 1.4, glassHeight + frame, frame),
392	      frameMat,
393	    );
394	    mullion.position.set(x, y, z);
395	    group.add(mullion);
396	  }
397	  for (const yy of [y - glassHeight / 2, y + glassHeight / 2]) {
398	    const rail = new THREE.Mesh(
399	      new THREE.BoxGeometry(thin * 1.4, frame, glassWidth + frame),
400	      frameMat,
401	    );
402	    rail.position.set(x, yy, (spec.zMin + spec.zMax) / 2);
403	    group.add(rail);
404	  }
405	  if (sillHeight > 0.01) {
406	    const sill = new THREE.Mesh(
407	      new THREE.BoxGeometry(thin * 1.4, sillHeight, depthM),
408	      spec.wallMat,
409	    );
410	    sill.position.set(x, spec.baseY + sillHeight / 2, (spec.zMin + spec.zMax) / 2);
411	    group.add(sill);
412	  }
413	}
414	
415	/** KRN-14 — gable roof for a dormer. */
416	export function buildGableDormerRoof(
417	  widthM: number,
418	  depthM: number,
419	  roofThickM: number,
420	  ridgeHeightM: number,
421	  ridgeAlongX: boolean,
422	  material: THREE.Material,
423	): THREE.Mesh {
424	  const longAlongWorldX = ridgeAlongX ? widthM >= depthM : depthM >= widthM;
425	  const hxWorld = ridgeAlongX ? widthM / 2 : depthM / 2;
426	  const hzWorld = ridgeAlongX ? depthM / 2 : widthM / 2;
427	  const eaveY = roofThickM;
428	  const ridgeY = eaveY + ridgeHeightM;
429	  const positions: number[] = [];
430	  const indices: number[] = [];
431	  if (longAlongWorldX) {
432	    positions.push(-hxWorld, eaveY, -hzWorld);
433	    positions.push(hxWorld, eaveY, -hzWorld);
434	    positions.push(hxWorld, eaveY, hzWorld);
435	    positions.push(-hxWorld, eaveY, hzWorld);
436	    positions.push(-hxWorld, ridgeY, 0);
437	    positions.push(hxWorld, ridgeY, 0);
438	    indices.push(0, 1, 5, 0, 5, 4);
439	    indices.push(2, 3, 4, 2, 4, 5);
440	    indices.push(0, 4, 3);
441	    indices.push(1, 2, 5);
442	  } else {
443	    positions.push(-hxWorld, eaveY, -hzWorld);
444	    positions.push(hxWorld, eaveY, -hzWorld);
445	    positions.push(hxWorld, eaveY, hzWorld);
446	    positions.push(-hxWorld, eaveY, hzWorld);
447	    positions.push(0, ridgeY, -hzWorld);
448	    positions.push(0, ridgeY, hzWorld);
449	    indices.push(1, 2, 5, 1, 5, 4);
450	    indices.push(3, 0, 4, 3, 4, 5);
451	    indices.push(0, 1, 4);
452	    indices.push(2, 3, 5);
453	  }
454	  const geom = new THREE.BufferGeometry();
455	  geom.setAttribute('position', new THREE.Float32BufferAttribute(positions, 3));
456	  geom.setIndex(indices);
457	  geom.computeVertexNormals();
458	  return new THREE.Mesh(geom, material);
459	}
460	
461	/** KRN-14 — hipped roof for a dormer (ridge shorter than the eave). */
462	export function buildHippedDormerRoof(
463	  widthM: number,
464	  depthM: number,
465	  roofThickM: number,
466	  ridgeHeightM: number,
467	  ridgeAlongX: boolean,
468	  material: THREE.Material,
469	): THREE.Mesh {
470	  const longAlongWorldX = ridgeAlongX ? widthM >= depthM : depthM >= widthM;
471	  const hxWorld = ridgeAlongX ? widthM / 2 : depthM / 2;
472	  const hzWorld = ridgeAlongX ? depthM / 2 : widthM / 2;
473	  const eaveY = roofThickM;
474	  const ridgeY = eaveY + ridgeHeightM;
475	  const longHalf = longAlongWorldX ? hxWorld : hzWorld;
476	  const ridgeHalf = Math.max(0.05, longHalf * 0.5);
477	  const positions: number[] = [];
478	  const indices: number[] = [];
479	  if (longAlongWorldX) {
480	    positions.push(-hxWorld, eaveY, -hzWorld);
481	    positions.push(hxWorld, eaveY, -hzWorld);
482	    positions.push(hxWorld, eaveY, hzWorld);
483	    positions.push(-hxWorld, eaveY, hzWorld);
484	    positions.push(-ridgeHalf, ridgeY, 0);
485	    positions.push(ridgeHalf, ridgeY, 0);
486	    indices.push(0, 1, 5, 0, 5, 4);
487	    indices.push(2, 3, 4, 2, 4, 5);
488	    indices.push(3, 0, 4);
489	    indices.push(1, 2, 5);
490	  } else {
491	    positions.push(-hxWorld, eaveY, -hzWorld);
492	    positions.push(hxWorld, eaveY, -hzWorld);
493	    positions.push(hxWorld, eaveY, hzWorld);
494	    positions.push(-hxWorld, eaveY, hzWorld);
495	    positions.push(0, ridgeY, -ridgeHalf);
496	    positions.push(0, ridgeY, ridgeHalf);
497	    indices.push(1, 2, 5, 1, 5, 4);
498	    indices.push(3, 0, 4, 3, 4, 5);
499	    indices.push(0, 1, 4);
500	    indices.push(2, 3, 5);
501	  }
502	  const geom = new THREE.BufferGeometry();
503	  geom.setAttribute('position', new THREE.Float32BufferAttribute(positions, 3));
504	  geom.setIndex(indices);
505	  geom.computeVertexNormals();
506	  return new THREE.Mesh(geom, material);
